import{_ as t,o as r,c as a,ag as o}from"./chunks/framework.BLeoozAw.js";const s="/Awesome-SRC-experience/img/640.png",p="/Awesome-SRC-experience/img/%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20241105232010.png",n="/Awesome-SRC-experience/img/%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20241105232023.png",i="/Awesome-SRC-experience/img/%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20241105232029.png",x=JSON.parse('{"title":"短信轰炸：微信小程序逻辑漏洞","description":"Awesome SRC Experience - 短信轰炸：微信小程序逻辑漏洞","frontmatter":{"title":"短信轰炸：微信小程序逻辑漏洞","description":"Awesome SRC Experience - 短信轰炸：微信小程序逻辑漏洞"},"headers":[],"relativePath":"experience/短信验证码/sms-logic-flaw.md","filePath":"experience/短信验证码/sms-logic-flaw.md"}'),g={name:"experience/短信验证码/sms-logic-flaw.md"};function c(m,e,l,_,h,E){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="短信轰炸-微信小程序逻辑漏洞" tabindex="-1">短信轰炸：微信小程序逻辑漏洞 <a class="header-anchor" href="#短信轰炸-微信小程序逻辑漏洞" aria-label="Permalink to &quot;短信轰炸：微信小程序逻辑漏洞&quot;">​</a></h1><h2 id="漏洞产生点" tabindex="-1">漏洞产生点： <a class="header-anchor" href="#漏洞产生点" aria-label="Permalink to &quot;漏洞产生点：&quot;">​</a></h2><p>微信小程序登录页面。</p><h2 id="漏洞复现" tabindex="-1">漏洞复现： <a class="header-anchor" href="#漏洞复现" aria-label="Permalink to &quot;漏洞复现：&quot;">​</a></h2><p><strong>正常登录流程：（有限制）</strong></p><p>小程序—&gt;登录—&gt;微信绑定手机号—&gt;继续—&gt;短信—&gt;验证—&gt;登录成功/登录失败；</p><p>小程序—&gt;登录—&gt;不允许获取手机号—&gt;结束；</p><p><strong>错误登录流程：（没有限制）</strong></p><p>小程序—&gt;登录—&gt;不允许—&gt;结束—&gt;使用其他手机号进行登录—&gt;输入手机号—&gt;图形验证码—&gt;验证码—&gt;重发即可</p><p><strong>测试截图：</strong></p><p><img src="'+s+'" alt=""></p><p><img src="'+p+'" alt=""></p><p><img src="'+n+'" alt=""></p><p><img src="'+i+'" alt=""></p><h2 id="修复建议" tabindex="-1">修复建议： <a class="header-anchor" href="#修复建议" aria-label="Permalink to &quot;修复建议：&quot;">​</a></h2><p><strong>发送频率限制：</strong></p><p>在服务端设置发送频率限制，例如每分钟只能发送一条短信，并对单个用户（或IP）设置最大发送条数限制，如每天不超过5条。这可以有效防止恶意用户通过连续发送请求来进行短信轰炸。</p><p><strong>原文链接：<a href="https://mp.weixin.qq.com/s/8mgOzhc2PeQPAuXrT5vY8Q" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/8mgOzhc2PeQPAuXrT5vY8Q</a></strong></p>',18)])])}const f=t(g,[["render",c]]);export{x as __pageData,f as default};
